AnimatedVisibility( visible = isExpanded, enter = slideInHorizontally(initialOffsetX = { it }) + fadeIn(), exit = slideOutHorizontally(targetOffsetX = { it }) + fadeOut(), modifier = Modifier .align(Alignment.TopEnd) .fillMaxHeight() ) { Column( modifier = Modifier .width(280.dp) .fillMaxHeight() .background( color = Color(0xFF3C3C3C), shape = RoundedCornerShape(topStart = 16.dp, bottomStart = 16.dp) ) .border( width = 1.dp, color = Color(0xFF5A5A5A), shape = RoundedCornerShape(topStart = 16.dp, bottomStart = 16.dp) ) .padding(top = 72.dp, bottom = 12.dp) ) { Text( text = "Menu", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold, color = Color(0xFFF2F2F2), modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp) )
